#!/usr/bin/perl
use strict;
use warnings FATAL => 'all';
use CGI qw(:standard);

print "Content-type text/html\n\n";

my $query = new CGI;
my $comment = $query->param('comment');
if (defined($comment)) {
    print "<div>$comment</div>";
} else {
    print 'No comment provided';
}